&lt;li&gt;&lt;a href=&#34;#%E7%B1%BB%E5%9E%8B%E5%8F%82%E6%95%B0-%E4%B8%BB%E7%B1%BB%E5%9E%8B%E4%B8%8D%E4%B8%80%E8%87%B4&#34;&gt;类型参数-主类型不一致&lt;/a&gt;&lt;/li&gt;
