&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;最小化除了当前窗口的所有窗口//所有窗口&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;win + home // D&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;预览桌面&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;win + ,&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;打开我的电脑//运行//控制中心&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;win + E//R//A&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;window 语音听写&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;win + H(hear)&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;锁屏&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;win + L(Lock)&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;电脑基本信息&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;win + pausebreak&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;hr&gt;
